import { PublicActionPage } from '@domain/publicActionPage';
import { useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { FormInputControl } from 'src/builder/PublicActionPage/components/FormInputControl';
import { Meta } from 'src/builder/PublicActionPage/components/Meta';
import { LoginLinkSection } from './LoginLinkSection';
import { MakeDonationAsSelector } from './MakeDonationAsSelector';

type Props = {
  actionPage?: PublicActionPage;
  displayOrganizationType?: boolean;
  includeOrganization?: boolean;
  isPreview?: boolean;
  requireOrganizationType?: boolean;
};

export const MakeDonationAsSection = ({
  actionPage,
  displayOrganizationType = false,
  includeOrganization = false,
  isPreview = false,
  requireOrganizationType = false,
}: Props) => {
  const { setValue, watch } = useFormContext();
  const { t } = useTranslation('customFields');
  const donorProfile = watch('donorProfile');
  const expressCheckoutMethod = watch('expressCheckoutMethod');
  const makeDonationAs = watch('makeDonationAs');
  const isInUpgradeChain = watch('isInUpgradeChain');

  const organizationLabel = useMemo(
    () =>
      makeDonationAs === 'business'
        ? t('name.businessName')
        : makeDonationAs === 'pac'
          ? t('name.pacName')
          : t('name.organizationName'),
    [makeDonationAs, t]
  );

  const organizationTypeLabel = useMemo(
    () => (makeDonationAs === 'business' ? t('name.businessType') : t('name.organizationType')),
    [makeDonationAs, t]
  );

  const isOrg = makeDonationAs === 'organization' || makeDonationAs === 'business';

  const isPac = makeDonationAs === 'pac';

  const showOrgName = isOrg || isPac;

  const showOrgType = displayOrganizationType && includeOrganization && isOrg;

  useEffect(() => {
    if (makeDonationAs === 'pac') {
      setValue('organizationType', 'PAC');
    } else {
      setValue('organizationType', '');
    }
  }, [makeDonationAs, setValue]);

  if (isInUpgradeChain) {
    return null;
  }

  return (
    <>
      <MakeDonationAsSelector actionPage={actionPage} includeOrganization={includeOrganization} />
      {actionPage && !expressCheckoutMethod && !donorProfile ? (
        <LoginLinkSection actionPage={actionPage} isPreview={isPreview} />
      ) : null}
      {showOrgName && (
        <FormInputControl
          formControlProps={{ className: 'mb-0' }}
          isRequired
          label={organizationLabel}
          name="organization"
        />
      )}
      {showOrgType && (
        <FormInputControl
          formControlProps={{ className: 'mb-0' }}
          isRequired={requireOrganizationType}
          label={organizationTypeLabel}
          name="organizationType"
        />
      )}
      {includeOrganization &&
      makeDonationAs !== 'individual' &&
      (!donorProfile?.firstName || !donorProfile?.lastName) ? (
        makeDonationAs === 'business' ? (
          <Meta variant="regular">{t('contact.business')}</Meta>
        ) : makeDonationAs === 'pac' ? (
          <Meta variant="regular">{t('contact.pac')}</Meta>
        ) : (
          <Meta variant="regular">{t('contact.organization')}</Meta>
        )
      ) : null}
    </>
  );
};

